225	    }
226	
227	    // Only valid for models with a decoder
228	    const kv_cache_dtype_config = custom_config.kv_cache_dtype;
229	    const kv_cache_dtype = kv_cache_dtype_config
230	        ? (typeof kv_cache_dtype_config === 'string'
