237	    }
238	
239	    const session_config = {
240	        dtype: selectedDtype,
241	        kv_cache_dtype,
242	        device: selectedDevice,
243	    }
244	
245	    // Construct the model file name
246	    const suffix = DEFAULT_DTYPE_SUFFIX_MAPPING[selectedDtype];
247	    const baseName = `${fileName}${suffix}.onnx`;
