289	            throw new Error(`The number of external data chunks (${num_chunks}) exceeds the maximum allowed value (${MAX_EXTERNAL_DATA_CHUNKS}).`);
290	        }
291	        for (let i = 0; i < num_chunks; ++i) {
292	            const path = `${baseName}_data${i === 0 ? '' : '_' + i}`;
293	            const fullPath = `${options.subfolder ?? ''}/${path}`;
294	            externalDataPromises.push(new Promise(async (resolve, reject) => {
295	                const data = await getModelFile(pretrained_model_name_or_path, fullPath, true, options, return_path);
296	                resolve(data instanceof Uint8Array ? { path, data } : path);
297	            }));
298	        }
299	
300	    } else if (session_options.externalData !== undefined) {
301	        externalDataPromises = session_options.externalData.map(async (ext) => {
