```

### 5. **The Generate Method Pattern**

**File:** `/src/models.js` (lines 1735-1944)

The `generate()` method is the core of generation:

- **Entry point:** Accepts `inputs`, `generation_config`, `logits_processor`, `stopping_criteria`, plus `**kwargs`
- **Key steps:**
  1. Prepare generation config
  2. Process model inputs via `_prepare_model_inputs()`
  3. For encoder-decoder models: prepare encoder outputs
  4. Prepare decoder input IDs
  5. Main generation loop with autoregressive token sampling
  6. Returns `sequences` tensor or dict with attentions/past_key_values

### 6. **Multimodal Input Handling - The Forward Chain**

**File:** `/src/models.js` (lines 718-827)

The critical flow for image-text-to-text models:

```javascript
// Step 1: imageTextToTextForward() delegates to genericTextToTextForward()
async function imageTextToTextForward(self, params) {
    return await genericTextToTextForward(self, {
        ...params,
        modality_input_name: 'pixel_values',      // ← Key
        modality_output_name: 'image_features',   // ← Key
        encode_function: self.encode_image.bind(self),
        merge_function: self._merge_input_ids_with_image_features.bind(self),
    });
}

// Step 2: genericTextToTextForward() orchestrates:
async function genericTextToTextForward(self, {
    encode_function,
    merge_function,
    modality_input_name,
    modality_output_name,
    input_ids, attention_mask, position_ids, inputs_embeds, past_key_values,
    ...kwargs
}) {
    // 1. Text encoding
    inputs_embeds = await self.encode_text({ input_ids, ...kwargs });

    // 2. Image encoding (if pixel_values present)
    if (modality_values && input_ids.dims[1] !== 1) {
        const modality_features = await encode_function({
            [modality_input_name]: modality_values,
            ...kwargs
        });

        // 3. Merge text embeddings + image features
        ({ inputs_embeds, attention_mask } = merge_function({
            [modality_output_name]: modality_features,
            inputs_embeds,
            input_ids,
            attention_mask,
        }));
    }

    // 4. Decoder forward using merged inputs
    const outputs = await decoderForward(self, {
        inputs_embeds,
        past_key_values,
        attention_mask,
        position_ids,
    }, true);
    return outputs;
}
```

